	private static void assertRecordedOnMovesFirst(List<String> mandatoryLeafOrder, TupleExpr optimized) {
		int recordedOnIndex = recordedOnIndex(mandatoryLeafOrder);
		int handledByIndex = mandatoryLeafOrder.indexOf(MEDICAL_HANDLED_BY_LABEL);
		int typeIndex = mandatoryLeafOrder.indexOf(MEDICAL_TYPE_LABEL);

		assertTrue(recordedOnIndex >= 0,
				"Expected optimized q2 plan to keep the recordedOn constraint explicit");
		assertTrue(handledByIndex >= 0 && typeIndex >= 0,
				"Expected optimized q2 plan to retain handledBy and rdf:type in the mandatory prefix");
		assertTrue(recordedOnIndex < handledByIndex && recordedOnIndex < typeIndex,
				"Expected optimized q2 plan to prepare recordedOn before handledBy and rdf:type once learned/sample selectivity is available: "
						+ mandatoryLeafOrder + "\n" + optimized);
	}

	private static int recordedOnIndex(List<String> mandatoryLeafOrder) {
		int recordedOnFilterIndex = mandatoryLeafOrder.indexOf(MEDICAL_RECORDED_ON_FILTER);
		if (recordedOnFilterIndex >= 0) {
			return recordedOnFilterIndex;
		}
		return mandatoryLeafOrder.indexOf(MEDICAL_RECORDED_ON_LABEL);
	}

	private static void assertSubstationNameMovesFirst(List<String> mandatoryLeafOrder) {
		int nameIndex = mandatoryLeafOrder.indexOf(GRID_SUBSTATION_NAME_FILTER);
		int feedsIndex = mandatoryLeafOrder.indexOf(GRID_FEEDS_LABEL);
		int typeIndex = mandatoryLeafOrder.indexOf(GRID_TRANSFORMER_TYPE_LABEL);

		assertTrue(nameIndex >= 0,
				"Expected optimized electrical q2 plan to keep the substation-name constraint explicit");
		assertTrue(feedsIndex >= 0 && typeIndex >= 0,
				"Expected optimized electrical q2 plan to retain feeds and transformer rdf:type in the mandatory prefix");
		assertTrue(nameIndex < feedsIndex && nameIndex < typeIndex,
				"Expected optimized electrical q2 plan to start with the selective substation-name lookup once evidence is available: "
						+ mandatoryLeafOrder);
	}

	private static BindingSetAssignment findBindingSetAssignment(TupleExpr optimized, String bindingName) {
		List<BindingSetAssignment> matches = new ArrayList<>(1);
		optimized.visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(BindingSetAssignment node) {
				if (matches.isEmpty() && node.getBindingNames().contains(bindingName)) {
					matches.add(node);
				}
				super.meet(node);
			}
		});
		return matches.isEmpty() ? null : matches.getFirst();
	}

	private static StatementPattern findStatementPattern(TupleExpr optimized, IRI predicate, String objectBindingName) {
		List<StatementPattern> matches = new ArrayList<>(1);
		optimized.visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(StatementPattern node) {
				if (matches.isEmpty()
						&& node.getPredicateVar() != null
						&& predicate.equals(node.getPredicateVar().getValue())
						&& node.getObjectVar() != null
						&& objectBindingName.equals(node.getObjectVar().getName())) {
					matches.add(node);
				}
				super.meet(node);
			}
		});
		return matches.isEmpty() ? null : matches.getFirst();
	}

	private static Filter findFirstRecordedOnFilter(TupleExpr optimized) {
		List<Filter> matches = new ArrayList<>(1);
		optimized.visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(Filter node) {
				if (matches.isEmpty() && isRecordedOnFilter(node)) {
					matches.add(node);
				}
				super.meet(node);
			}
		});
		return matches.isEmpty() ? null : matches.getFirst();
	}

	private static void assertLiteralValues(BindingSetAssignment assignment, String bindingName,
			String... expectedLabels) {
		List<String> actualLabels = literalValues(assignment, bindingName);
		assertEquals(List.of(expectedLabels), actualLabels);
	}

	private static List<String> literalValues(BindingSetAssignment assignment, String bindingName) {
		List<String> labels = new ArrayList<>();
		for (BindingSet bindingSet : assignment.getBindingSets()) {
			Value value = bindingSet.getValue(bindingName);
			if (value instanceof Literal) {
				labels.add(((Literal) value).getLabel());
			}
		}
		return labels;
	}

	private static void loadLibraryData(SailRepository repository) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.begin(IsolationLevels.NONE);

			List<Resource> branches = new ArrayList<>(100);
			for (int i = 0; i < 100; i++) {
				Resource branch = VF.createIRI("urn:test:branch:" + i);
				branches.add(branch);
				connection.add(branch, NAME, VF.createLiteral("Branch " + i));
			}

			for (int i = 0; i < 40; i++) {
				Resource copy = VF.createIRI("urn:test:copy:" + i);
				Resource branch = branches.get(i % 2);
				connection.add(copy, RDF_TYPE, COPY);
				connection.add(copy, LOCATED_AT, branch);
			}

			for (int i = 0; i < 50; i++) {
				Resource noise = VF.createIRI("urn:test:noise:" + i);
				connection.add(noise, LOCATED_AT, branches.get(2 + (i % 20)));
			}

			connection.commit();
		}
	}

	private static void loadFiniteChainData(SailRepository repository) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.begin(IsolationLevels.NONE);
			IRI a = VF.createIRI("urn:test:a");
			IRI b = VF.createIRI("urn:test:b");
			IRI predicate = VF.createIRI("urn:test:p");
			connection.add(a, predicate, b);
			connection.add(b, predicate, a);
			connection.commit();
		}
	}

	private static void loadValuesLocalityData(SailRepository repository) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.begin(IsolationLevels.NONE);
			for (int entityIndex = 0; entityIndex < 12; entityIndex++) {
				for (int valueIndex = 0; valueIndex < 10; valueIndex++) {
					if (valueIndex % 2 == 0) {
						connection.add(valuesLocalityValue(valueIndex, entityIndex),
								valuesLocalityPredicate(valueIndex),
								VF.createIRI("urn:test:tail:" + valueIndex + ":" + entityIndex));
					} else {
						connection.add(VF.createIRI("urn:test:carrier:" + valueIndex + ":" + entityIndex),
								valuesLocalityPredicate(valueIndex), valuesLocalityValue(valueIndex, entityIndex));
					}
				}
			}
			connection.commit();
		}
	}

	private static long evaluateCount(SailRepository repository, String query) {
		try (SailRepositoryConnection connection = repository.getConnection();
				TupleQueryResult result = connection.prepareTupleQuery(query).evaluate()) {
			assertTrue(result.hasNext(), "Aggregate count query should return one result row");
			BindingSet bindingSet = result.next();
			assertTrue(!result.hasNext(), "Aggregate count query should return only one result row");
			return ((Literal) bindingSet.getValue("count")).longValue();
		}
	}

	private static String valuesLocalityQuery() {
		return String.join("\n",
				"PREFIX ex: <urn:test:>",
				"SELECT (COUNT(*) AS ?count) WHERE {",
				"  VALUES ?v0 { " + iriList(0) + " }",
				"  ?v0 ex:p0 ?tail0 .",
				"  ?carrier1 ex:p1 ?v1 .",
				"  FILTER (?v1 IN (" + commaIriList(1) + "))",
				"  VALUES ?v2 { " + iriList(2) + " }",
				"  ?v2 ex:p2 ?tail2 .",
				"  ?carrier3 ex:p3 ?v3 .",
				"  FILTER (?v3 IN (" + commaIriList(3) + "))",
				"  VALUES ?v4 { " + iriList(4) + " }",
				"  ?v4 ex:p4 ?tail4 .",
				"  ?carrier5 ex:p5 ?v5 .",
				"  FILTER (?v5 IN (" + commaIriList(5) + "))",
				"  VALUES ?v6 { " + iriList(6) + " }",
				"  ?v6 ex:p6 ?tail6 .",
				"  ?carrier7 ex:p7 ?v7 .",
				"  FILTER (?v7 IN (" + commaIriList(7) + "))",
				"  VALUES ?v8 { " + iriList(8) + " }",
				"  ?v8 ex:p8 ?tail8 .",
				"  ?carrier9 ex:p9 ?v9 .",
				"  FILTER (?v9 IN (" + commaIriList(9) + "))",
				"}");
	}

	private static String iriList(int valueIndex) {
		List<String> values = new ArrayList<>(12);
		for (int i = 0; i < 12; i++) {
			values.add("<" + valuesLocalityValue(valueIndex, i) + ">");
		}
		return String.join(" ", values);
	}

	private static String commaIriList(int valueIndex) {
		List<String> values = new ArrayList<>(12);
		for (int i = 0; i < 12; i++) {
			values.add("<" + valuesLocalityValue(valueIndex, i) + ">");
		}
		return String.join(", ", values);
	}

	private static IRI valuesLocalityValue(int valueIndex, int constantIndex) {
		return VF.createIRI("urn:test:v" + valueIndex + "-" + constantIndex);
	}

	private static IRI valuesLocalityPredicate(int valueIndex) {
		return VF.createIRI("urn:test:p" + valueIndex);
	}

